"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { motion, AnimatePresence } from "framer-motion";
import { ThemeToggle } from "./ThemeToggle";
import { Command } from "lucide-react";
import { useState, useEffect, useRef } from "react";
import { CommandMenu } from "./CommandMenu";

// ---------------------------------------------------------------------------
// Nav links
// ---------------------------------------------------------------------------

const links = [
    { name: "Home",  path: "/"         },
    { name: "About", path: "/about"    },
    { name: "Work",  path: "/projects" },
    { name: "Blogs", path: "/blog"     },
];

// ---------------------------------------------------------------------------
// Navbar
// ---------------------------------------------------------------------------

export function Navbar() {
    const [isCommandOpen, setIsCommandOpen] = useState(false);
    const [isScrolled,    setIsScrolled]    = useState(false);
    const [hoveredPath,   setHoveredPath]   = useState<string | null>(null);
    const [moreOpen,      setMoreOpen]      = useState(false);
    const moreRef = useRef<HTMLLIElement>(null);
    const pathname = usePathname();

    // ── Effects ────────────────────────────────────────────────────────────

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if ((e.metaKey || e.ctrlKey) && e.key === "k") {
                e.preventDefault();
                setIsCommandOpen((prev) => !prev);
            }
            if (e.key === "Escape") setMoreOpen(false);
        };

        const handleScroll = () => setIsScrolled(window.scrollY > 100);

        const handleClickOutside = (e: MouseEvent) => {
            if (moreRef.current && !moreRef.current.contains(e.target as Node)) {
                setMoreOpen(false);
            }
        };

        window.addEventListener("keydown",     handleKeyDown);
        window.addEventListener("scroll",      handleScroll, { passive: true });
        document.addEventListener("mousedown", handleClickOutside);

        handleScroll();

        return () => {
            window.removeEventListener("keydown",     handleKeyDown);
            window.removeEventListener("scroll",      handleScroll);
            document.removeEventListener("mousedown", handleClickOutside);
        };
    }, []);

    // ── Active link check ──────────────────────────────────────────────────

    const isActive = (path: string) => {
        if (path === "/") return pathname === "/";
        return pathname === path || pathname.startsWith(path + "/");
    };

    return (
        <>
            <motion.header
                initial={{ y: -100, opacity: 0 }}
                animate={{ y: 0,    opacity: 1 }}
                transition={{ duration: 0.8, ease: "easeOut" }}
                className="fixed top-0 left-0 right-0 z-50 px-6 py-6 pointer-events-none"
            >
                {/*
                    NOT scrolled → max-w-[1400px] full-width, justify-between
                                   (logo left, nav middle-right, controls right)
                    Scrolled     → shrinks to fit-content, mx-auto centers it,
                                   all items sit inline with a small gap.
                                   The tagline fades out to keep it compact.
                */}
                <motion.div
                    layout
                    transition={{ type: "spring", stiffness: 280, damping: 28 }}
                    className={`pointer-events-auto flex items-center transition-all duration-300 ${
                        isScrolled
                            ? "w-fit mx-auto gap-3 md:gap-4 bg-white/80 dark:bg-[#111]/80 backdrop-blur-md border border-neutral-200 dark:border-[#222] rounded-full px-4 py-2 shadow-md"
                            : "max-w-[1400px] mx-auto justify-between"
                    }`}
                >

                    {/* ── Left: Logo + tagline ─────────────────────────── */}
                    <div className="flex items-center space-x-4">
                        <div className="text-2xl font-serif italic font-bold text-black dark:text-white">PM</div>
                        <div
                            className={`hidden sm:flex flex-col transition-all duration-500 ${
                                isScrolled
                                    ? "opacity-0 w-0 overflow-hidden pointer-events-none"
                                    : "opacity-100"
                            }`}
                        >
                            <span className="text-[10px] tracking-widest font-semibold text-neutral-500 dark:text-neutral-400">
                                CREATIVE ENGINEER
                            </span>
                            <div className="flex items-center space-x-1.5 mt-0.5">
                                <span className="w-1.5 h-1.5 rounded-full bg-green-500 animate-[pulse_2s_ease-in-out_infinite]" />
                                <span className="text-[10px] tracking-widest font-semibold text-green-600 dark:text-green-500">
                                    BUILDING THE FUTURE
                                </span>
                            </div>
                        </div>
                    </div>

                    {/* ── Nav pill ─────────────────────────────────────── */}
                    <nav
                        className={`hidden md:flex items-center px-1.5 py-1.5 rounded-full backdrop-blur-md border shadow-sm transition-colors duration-300 ${
                            isScrolled
                                ? "bg-transparent border-transparent shadow-none"
                                : "bg-neutral-100/90 dark:bg-[#111]/90 border-neutral-200 dark:border-[#222]"
                        }`}
                    >
                        <ul
                            className="flex items-center relative"
                            onMouseLeave={() => setHoveredPath(null)}
                        >
                            {links.map((link) => {
                                const active   = isActive(link.path);
                                const showPill = hoveredPath === link.path
                                    || (hoveredPath === null && active);

                                return (
                                    <li
                                        key={link.name}
                                        className="relative"
                                        onMouseEnter={() => setHoveredPath(link.path)}
                                    >
                                        <Link
                                            href={link.path}
                                            className={`relative px-5 py-2 text-sm font-medium transition-colors duration-300 rounded-full flex items-center justify-center z-10 ${
                                                showPill
                                                    ? "text-white dark:text-[#111]"
                                                    : "text-neutral-600 dark:text-neutral-400 hover:text-black dark:hover:text-white"
                                            }`}
                                        >
                                            {link.name}
                                        </Link>

                                        {showPill && (
                                            <motion.div
                                                layoutId="nav-pill"
                                                className="absolute inset-0 bg-[#111] dark:bg-white rounded-full shadow-sm -z-10"
                                                transition={{ type: "spring", stiffness: 350, damping: 30 }}
                                            />
                                        )}
                                    </li>
                                );
                            })}

                            <li
                                ref={moreRef}
                                className="relative"
                                onMouseEnter={() => { setHoveredPath("more"); setMoreOpen(true);  }}
                                onMouseLeave={() => { setMoreOpen(false); }}
                            >
                                <button
                                    onClick={() => setMoreOpen((p) => !p)}
                                    onFocus={() => setMoreOpen(true)}
                                    aria-haspopup="true"
                                    aria-expanded={moreOpen}
                                    className={`px-5 py-2 text-sm font-medium transition-all duration-300 rounded-full flex items-center relative z-10 space-x-1 outline-none focus-visible:ring-2 focus-visible:ring-neutral-400 ${
                                        hoveredPath === "more"
                                            ? "text-white dark:text-[#111]"
                                            : "text-neutral-600 dark:text-neutral-400 hover:text-black dark:hover:text-white"
                                    }`}
                                >
                                    <span>More</span>
                                    <motion.svg
                                        width="10" height="6" viewBox="0 0 10 6"
                                        fill="none"
                                        animate={{ rotate: moreOpen ? 180 : 0 }}
                                        transition={{ duration: 0.2 }}
                                        className="mt-0.5 opacity-50"
                                    >
                                        <path d="M1 1L5 5L9 1" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
                                    </motion.svg>
                                </button>

                                {hoveredPath === "more" && (
                                    <motion.div
                                        layoutId="nav-pill"
                                        className="absolute inset-0 bg-[#111] dark:bg-white rounded-full shadow-sm -z-10"
                                        transition={{ type: "spring", stiffness: 350, damping: 30 }}
                                    />
                                )}

                                {/* Dropdown */}
                                <AnimatePresence>
                                    {moreOpen && (
                                        <motion.div
                                            initial={{ opacity: 0, y: -8, scale: 0.95 }}
                                            animate={{ opacity: 1, y: 0,  scale: 1    }}
                                            exit={{    opacity: 0, y: -8, scale: 0.95 }}
                                            transition={{ duration: 0.15, ease: "easeOut" }}
                                            className="absolute top-full left-1/2 -translate-x-1/2 pt-4 w-48 z-50"
                                        >
                                            <div className="bg-white dark:bg-[#111] border border-neutral-200 dark:border-[#333] rounded-2xl shadow-xl overflow-hidden p-2 flex flex-col items-start">
                                                <Link
                                                    href="/contact"
                                                    onClick={() => setMoreOpen(false)}
                                                    className="w-full text-left px-4 py-2 text-sm font-medium text-neutral-600 dark:text-neutral-400 hover:text-black dark:hover:text-white hover:bg-neutral-100 dark:hover:bg-[#222] rounded-xl transition-colors mb-1 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-neutral-400"
                                                >
                                                    Contact Me
                                                </Link>

                                                <a
                                                    href="/resume.pdf"
                                                    target="_blank"
                                                    rel="noopener noreferrer"
                                                    onClick={() => setMoreOpen(false)}
                                                    className="w-full text-left px-4 py-2 text-sm font-medium text-neutral-600 dark:text-neutral-400 hover:text-black dark:hover:text-white hover:bg-neutral-100 dark:hover:bg-[#222] rounded-xl transition-colors mb-1 flex items-center justify-between group/resume focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-neutral-400"
                                                >
                                                    <span>Resume</span>
                                                    <svg className="w-3 h-3 opacity-40 group-hover/resume:opacity-100 transition-opacity" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                                        <path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4M7 10l5 5 5-5M12 15V3"/>
                                                    </svg>
                                                </a>

                                                <div className="w-full h-px bg-neutral-200 dark:bg-[#333] my-1" />

                                                <div className="w-full px-4 py-2">
                                                    <p className="text-[10px] font-bold tracking-wider text-neutral-400 dark:text-neutral-500 uppercase mb-2">
                                                        Links
                                                    </p>
                                                    <div className="flex flex-col space-y-1 -mx-2">
                                                        {[
                                                            { label: "LinkedIn", href: "https://linkedin.com/in/peshalmishra"  },
                                                            { label: "GitHub",   href: "https://github.com/peshalmishra"       },
                                                            { label: "Twitter",  href: "https://twitter.com/peshalmishra"      },
                                                        ].map((item) => (
                                                            <a
                                                                key={item.label}
                                                                href={item.href}
                                                                target="_blank"
                                                                rel="noopener noreferrer"
                                                                onClick={() => setMoreOpen(false)}
                                                                className="w-full text-left px-2 py-1.5 text-sm font-medium text-neutral-600 dark:text-neutral-400 hover:text-black dark:hover:text-white hover:bg-neutral-100 dark:hover:bg-[#222] rounded-lg transition-colors flex items-center justify-between group/link focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-neutral-400"
                                                            >
                                                                {item.label}
                                                                <svg
                                                                    className="w-3 h-3 opacity-0 -translate-x-2 group-hover/link:opacity-100 group-hover/link:translate-x-0 transition-all"
                                                                    viewBox="0 0 24 24" fill="none" stroke="currentColor"
                                                                    strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"
                                                                >
                                                                    <path d="M5 12h14M12 5l7 7-7 7" />
                                                                </svg>
                                                            </a>
                                                        ))}
                                                    </div>
                                                </div>
                                            </div>
                                        </motion.div>
                                    )}
                                </AnimatePresence>
                            </li>
                        </ul>
                    </nav>

                    {/* ── Right: Controls ──────────────────────────────── */}
                    <div className="flex items-center space-x-3 md:space-x-4">

                        {/* Theme toggle */}
                        <div className="w-10 h-10 rounded-full border border-neutral-200 dark:border-[#333] flex items-center justify-center bg-white dark:bg-[#111] shadow-sm hidden sm:flex">
                            <ThemeToggle />
                        </div>

                        {/* Book a Call */}
                        <Link
                            href="/contact"
                            className="hidden sm:flex px-5 py-2.5 text-sm font-medium text-white bg-[#111] dark:text-[#111] dark:bg-[#ededed] rounded-full hover:bg-black dark:hover:bg-white transition-colors shadow-sm whitespace-nowrap"
                        >
                            Book a Call
                        </Link>

                        {/* Command menu trigger */}
                        <button
                            onClick={() => setIsCommandOpen(true)}
                            aria-label="Open command menu (⌘K)"
                            className="w-10 h-10 rounded-full border border-neutral-200 dark:border-[#333] flex items-center justify-center text-neutral-600 dark:text-neutral-400 hover:text-black dark:hover:text-white hover:bg-neutral-100 dark:hover:bg-[#222] transition-colors shadow-sm bg-white dark:bg-[#111]"
                        >
                            <Command className="w-4 h-4" />
                        </button>
                    </div>

                </motion.div>
            </motion.header>

            <CommandMenu isOpen={isCommandOpen} onClose={() => setIsCommandOpen(false)} />
        </>
    );
}